void wt2hbm_BLOCK00_q_weight (HANDLE device, HANDLE h2cx, char* path) {
  char real_path[100];
  for (uint64_t port = 0; port < 32; port++) {
    sprintf(real_path, path, int(port));
    DDR_Write_bin(h2cx, real_path, 8610449408, 270336);
    uint64_t hbm_out_addr = 0 + 268435456 * port;
    for (int i = 0; i < 5; i++) {
      CSB_Write(device, 64+4, 20514816+i*65536);
      CSB_Write(device, 64+5, ((uint32_t*)(&hbm_out_addr))[0]);
      CSB_Write(device, 64+6, ((uint32_t*)(&hbm_out_addr))[1]);
      CSB_Write(device, 64+7, (i < 4) ? 524288 : 65536);
      CSB_Write(device, 64+8, port);
      CSB_Write(device, 64+9, 2);
      hbm_out_addr += 65536;
      while(CSB_Read(device, 64) != 1) {}
    }
  }
  init(h2cx, 8610449408, 270336);
}

